create table dirkspzm32.edi_vda4987_hu_group (
    document_id              varchar2(32 char) not null enable,
    hug_id                   varchar2(32 char) default sys_guid() not null enable,
    pos                      number(4, 0) not null enable,
    package_qty              number(3, 0),
    terms_cond_code          varchar2(3 char),
    type_desc_code           varchar2(7 char),
    pack_code_supplier       varchar2(35 char),
    qty_stacking_factor      number(3, 0),
    number_of_pack_materials number(3, 0)
);

alter table dirkspzm32.edi_vda4987_hu_group
    add constraint pk_edi_vda4987_hu_group primary key ( hug_id )
        using index enable;


